#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, k; scanf("%d %d", &n, &k);
        int *a = (int*)malloc(n * sizeof(int));
        int *tmp = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &a[i]);
        if (n) k %= n; else k = 0;
        for (int i = 0; i < n; ++i) tmp[(i + k) % n] = a[i];
        for (int i = 0; i < n; ++i) {
            if (i) printf(" ");
            printf("%d", tmp[i]);
        }
        printf("\n");
        free(a);
        free(tmp);
    }
    return 0;
}

