import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        k = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        if n:
            k %= n
        else:
            k = 0
        tmp = [0] * n
        for i in range(n):
            tmp[(i + k) % n] = arr[i]
        out_lines.append(' '.join(map(str, tmp)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

